INSERT INTO `books` VALUES (1117,'9780521686457','Jojo\'s Story Level 2 Elementary/Lower Intermediate Book and Audio CD Pack','Antoinette Moses','\'There aren\'t any more days. There\'s just time. Time when it\'s dark and time when it\'s light. Everything is dead, so why not days too?\" Everyone in Jojo\'s village is dead, and ten-year-old Jojo is alone.','http://books.google.com/books/content?id=dRlVZWumj3UC&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:28','dRlVZWumj3UC',NULL,'Cambridge University Press',2006,'Foreign Language Study','NOT_MATURE','2.4.6.0.preview.1',52),(1118,'1662964587','JoJo\'s Special Bracelet','Anthony Mazzurco','With her birthday approaching, JoJo’s parents ask her to think about what kind of present she would like to receive. Since she enjoys looking at the charm bracelets of her friends in school, she decides that she would like a charm bracelet of her own. Her parents think that is a wonderful idea and ask JoJo to think about what charms she would like to have on her bracelet. JoJo’s Special Bracelet finds JoJo asking some of her neighbors to give her ideas about what her bracelet should look like. When her birthday finally arrives, JoJo discovers that her presents are even more special than she would have guessed. JoJo’s Special Bracelet, along with Anthony Mazzurco’s first book JoJo’s Wondrous New House (which appeared on the Amazon best-seller list and also received a 5-star review from The Book Revue), invite young readers and pre-readers, with the help of an adult, to enjoy the story and to think about what they might say or do along with the characters in the books.','http://books.google.com/books/content?id=cLRyEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:28','cLRyEQAAQBAJ',NULL,'Gatekeeper Press',2025,'Juvenile Fiction','NOT_MATURE','1.1.1.0.preview.2',24),(1119,'1662952910','JoJo\'s Wondrous New House','Anthony Mazzurco','JoJo’s family just bought a house from family friends. While everyone is busy moving in, JoJo excitedly decides to explore her new home and learns that it holds some wonderful, unexpected surprises. Young readers with vivid imaginations and pre-readers (with the help of an older reader) are invited to follow along with JoJo as she tries to think of ways to enjoy the surprises her new home has to offer.','http://books.google.com/books/content?id=nKwVEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:28','nKwVEQAAQBAJ',NULL,'Gatekeeper Press',2024,'Juvenile Fiction','NOT_MATURE','1.1.1.0.preview.3',30),(1120,'1974729206','JoJo’s Bizarre Adventure: Part 5--Golden Wind, Vol. 1','Hirohiko Araki','Golden Wind is here! The highly-acclaimed fifth arc of Hirohiko Araki’s JoJo’s Bizarre Adventure shifts the action from Japan to Italy, as Koichi Hirose heads to Europe to find an aspiring gangster named Giorno Giovanna, the secret son of Dio Brando, scourge of the Joestar family. Organized crime meets family drama and unbelievable enemy Stands in JoJo’s Bizarre Adventure: Part 5—Golden Wind! -- VIZ Media','http://books.google.com/books/content?id=RZo0EAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:29','RZo0EAAAQBAJ',NULL,'VIZ Media LLC',2021,'Comics & Graphic Novels','NOT_MATURE','1.4.4.0.preview.3',314),(1121,'1974714411','JoJo’s Bizarre Adventure: Part 4--Diamond Is Unbreakable, Vol. 3','Hirohiko Araki','Let’s go eat some Italian food! Josuke and the gang find themselves in hot water in a brand-new Italian restaurant thanks to its overly aggressive chef. Is he an enemy Stand user or just a foodie gone off the deep end? Plus, Josuke discovers that someone has been spying on every known Stand user in Morioh right before his absentee father, Joseph Joestar, comes to town, and the gang has to contend with Rohan Kishibe, a local mangaka who is a really bizarre individual! -- VIZ Media','http://books.google.com/books/content?id=0xi3DwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:29','0xi3DwAAQBAJ',NULL,'VIZ Media LLC',2019,'Comics & Graphic Novels','NOT_MATURE','2.3.2.0.preview.3',386),(1122,'1974721965','JoJo’s Bizarre Adventure: Part 4--Diamond Is Unbreakable, Vol. 6','Hirohiko Araki','Yukako Yamagishi still loves Koichi Hirose, despite how their last rendezvous turned out! She’s so desperate for his love that she may make a drastic decision in order to win his heart—a decision that could have disastrous consequences when a new Stand appears! Is this an enemy Stand, or is it going to help her in her quest? -- VIZ Media','http://books.google.com/books/content?id=eojyDwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:29','eojyDwAAQBAJ',NULL,'VIZ Media LLC',2020,'Comics & Graphic Novels','NOT_MATURE','2.4.3.0.preview.3',410),(1123,'1974756580','JoJo’s Bizarre Adventure: Part 7--Steel Ball Run, Vol. 1','Hirohiko Araki','Riders from around the world gather in the Wild West for the race of the century! Johnny Joestar, a former jockey paralyzed from the waist down, comes to spectate, and momentarily regains the ability to walk while watching a duel fought by Gyro Zeppeli. Desperate to learn more about this power, Johnny joins the race alongside Gyro and embarks on the most epic and bizarre race to ever cross the American frontier! -- VIZ Media','http://books.google.com/books/content?id=JiQoEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:29','JiQoEQAAQBAJ',NULL,'VIZ Media LLC',2025,'Comics & Graphic Novels','NOT_MATURE','1.2.2.0.preview.3',392),(1124,'197472378X','JoJo’s Bizarre Adventure: Part 4--Diamond Is Unbreakable, Vol. 7','Hirohiko Araki','Josuke’s bizarre adventure reaches new heights! Who is this person who claims to be an alien? Did Rohan really witness a grisly murder in a tunnel on the highway? Has Yoshikage Kira finally met his match after all these years—and is it a cat or a plant? Morioh is as chaotic as ever!','http://books.google.com/books/content?id=-HwEEAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:30','-HwEEAAAQBAJ',NULL,'VIZ Media LLC',2020,'Comics & Graphic Novels','NOT_MATURE','0.4.1.0.preview.3',392),(1125,'1974757285','JoJo’s Bizarre Adventure: Part 7--Steel Ball Run, Vol. 2','Hirohiko Araki','Gyro leads the race at the end of the first stage—but it’s too soon to celebrate just yet. Three competitors have turned up dead, and the famous cowboy Mountain Tim has just been deputized to find the culprits. Following the trail of horseshoe tracks, he sets his sights on Johnny and Gyro. But as the three men collide in the hostile Arizona d','http://books.google.com/books/content?id=ECkoEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:30','ECkoEQAAQBAJ',NULL,'VIZ Media LLC',2025,'Comics & Graphic Novels','NOT_MATURE','1.3.2.0.preview.3',410),(1126,'1974725502','JoJo’s Bizarre Adventure: Part 4--Diamond Is Unbreakable, Vol. 8','Hirohiko Araki','What kind of weirdo lives on a transmission tower?! An all-new enemy Stand attempts to trap, outwit and eliminate Josuke Higashikata and Okuyasu Nijimura, but Shining Diamond is a formidable foe! Then, the battle for Morioh turns personal when Koichi disappears. What else does this new enemy have in mind for the gang? Plus, Yoshikage Kira is still hiding, biding his time, eager to take another life... -- VIZ Media','http://books.google.com/books/content?id=8SUWEAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-14 19:30:30','8SUWEAAAQBAJ',NULL,'VIZ Media LLC',2021,'Comics & Graphic Novels','NOT_MATURE','1.5.4.0.preview.3',392),(1127,'1476674442','The Ages of The Flash','Joseph J. Darowski','While many American superheroes have multiple powers and complex gadgets, the Flash is simply fast. This simplicity makes his character easily comprehendible for all audiences, whether they are avid comic fans or newcomers to the genre, and in turn he has become one of the most iconic figures in the comic-book industry. This collection of new essays serves as a stepping-stone to an even greater understanding of the Flash, examining various iterations of his character--including those of Jay Garrick, Barry Allen, Wally West and Bart Allen--and what they reveal about the era in which they were written.','http://books.google.com/books/content?id=dzOXDwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','dzOXDwAAQBAJ','Essays on the Fastest Man Alive','McFarland',2019,'Literary Criticism','NOT_MATURE','0.1.2.0.preview.1',195),(1128,NULL,'The Flash: Season Zero (2014-) #21','Andrew Kreisberg','What was Leonard Snart like before he acquired his cold gun and became one of The Flash\'s most dangerous enemies? The origin of Captain Cold is revealed!','http://books.google.com/books/content?id=-rSeCQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','-rSeCQAAQBAJ',NULL,'DC',1970,'Comics & Graphic Novels','NOT_MATURE','1.4.2.0.preview.3',47),(1129,NULL,'The Flash (1959-1985) #224','Cary Bates','When Barry Allen’s friend is murdered running for district attorney on a campaign to root out mob ties in Central City, it’s the Flash who vows to bring his spirit justice-but is that the only spirit lurking in the shadows?','http://books.google.com/books/content?id=UFXQEAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','UFXQEAAAQBAJ',NULL,'DC Comics',1973,'Comics & Graphic Novels','NOT_MATURE','2.3.3.0.preview.3',22),(1130,NULL,'The Flash (1987-) #202','Geoff Johns','The Fastest Man Alive struggles to protect his fellow officers as the true identity of their killer is revealed.','http://books.google.com/books/content?id=mr-RBAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','mr-RBAAAQBAJ',NULL,'DC',1970,'Comics & Graphic Novels','NOT_MATURE','2.4.3.0.preview.3',24),(1131,'1401270883','The Flash: The Silver Age Vol. 2','John Broome','Written by John Broome (THE FLASH, GREEN LANTERN) and Robert Kanigher (SUICIDE SQUAD: THE SILVER AGE) and illustrated by Carmine Infantino and Joe Giella, THE FLASH: THE SILVER AGE VOL. 2 collects the era-defining adventures of the Scarlet Speedster. Police scientist Barry Allen always enjoyed the exploits of his favorite comic book crime-fighter, the Flash. But before lightning struck his lab and infused his body with the power of super-speed, he never dreamed he would follow in his hero’s footsteps! Fortunately for comics fans everywhere, that’s exactly what happened—and when DC’s revitalized Flash burst onto newsstands in 1956, he opened the door to a new age of excitement—a Silver Age of superheroes, spearheaded by legendary DC editor Julius Schwartz and his titanically talented team of creative collaborators. Now, for the first time, these groundbreaking Flash stories are available in an all-new series of comprehensive Omnibus editions. Collects THE FLASH #117-132.','http://books.google.com/books/content?id=-XmPEAAAQBAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 05:48:27','-XmPEAAAQBAJ',NULL,'National Geographic Books',2017,'Comics & Graphic Novels','NOT_MATURE','preview-1.0.0',0),(1132,'9781401258757','The Flash Vol. 7 (the New 52)','Robert Venditti','Out of time! The Flash is trapped in a bizarre, lost land terrorized by castaways from the past, present, and future. But that leaves Central City without a hero and, even worse, an all-new murderous Flash shows up to take Barry\'s place. With Barry Allen trapped in the Speed Force while an impostor wreaks havoc at home, will the Fastest Man Alive make it back in time to put things right? Collects THE FLASH #36-40 and SECRET ORIGINS #7.','http://books.google.com/books/content?id=GnV8rgEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 05:48:27','GnV8rgEACAAJ',NULL,NULL,2016,NULL,'NOT_MATURE','preview-1.0.0',144),(1133,'1683351983','The Flash: Hocus Pocus','Barry Lyga','Race into action in this all-new original adventure based on the hit CW TV series, The Flash! In a timeline where Flashpoint never happened, The Flash (aka Barry Allen) must face a mysterious villain who can control the minds and actions of citizens. But when Hocus Pocus, as he calls himself, takes control of Barry, it’s up to Team Flash to help the Scarlet Speedster before he’s forced to do the unthinkable. Written by New York Times bestselling author Barry Lyga, this is one adventure fans of the TV series won’t want to miss! THE FLASH and all related characters and elements are trademarks of and © DC Comics. (s17)','http://books.google.com/books/content?id=4YgwDwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','4YgwDwAAQBAJ','(The Flash Book 1)','Abrams',2017,'Juvenile Fiction','NOT_MATURE','1.5.5.0.preview.3',215),(1134,'168335253X','The Flash: Johnny Quick','Barry Lyga','Based on the hit CW TV show, this second title in The Flash middle-grade series follows Barry Allen as he continues his mission to protect Central City from the sinister Hocus Pocus—but this time, a new evil lurks beneath the city streets . . . Written by New York Times–bestselling author Barry Lyga, this brand-new, original adventure builds upon the world of The Flash. This is one fans won’t want to miss!','http://books.google.com/books/content?id=ZTpGDwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','ZTpGDwAAQBAJ','(The Flash Book 2)','Abrams',2018,'Juvenile Fiction','NOT_MATURE','1.7.6.0.preview.3',206),(1135,'1683359828','The Flash: The Legends of Forever (Crossover Crisis #3)','Barry Lyga','The Legends of Tomorrow enter the fray in this epic conclusion to the Crossover Crisis trilogy The Flash and his friends have defeated Anti-Matter Man, but the race to save the multiverse is far from over. As a threat looms large at the end of Time itself, Barry, his Kryptonian allies, and the Green Arrow seek help from the leading experts on time travel, the Legends of Tomorrow. Meanwhile, Cisco has been taken by a mysterious figure—and Owlman’s plans for Madame Xanadu come to a thrilling head. Picking right up where Supergirl’s Sacrifice left off, this action-packed adventure brings the Crossover Crisis to a dramatic conclusion beyond the end of the universe.','http://books.google.com/books/content?id=coDTDwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','coDTDwAAQBAJ',NULL,'Abrams',2021,'Juvenile Fiction','NOT_MATURE','1.4.5.0.preview.3',275),(1136,'0596554273','Flash CS4: The Missing Manual','Chris Grover','Unlock the power of Flash and bring gorgeous animations to life onscreen. It\'s easy with Flash CS4: The Missing Manual. You\'ll start creating animations in the first chapter, and will learn to produce effective, well-planned visuals that get your message across. This entertaining new edition includes a complete primer on animation, a guided tour of the program\'s tools, lots of new illustrations, and more details on working with video. Beginners will learn to use the software in no time, and experienced Flash designers will improve their skills. Expanded and revised to cover the new version of Flash, every chapter in this book provides step-by-step tutorials to help you: Learn to draw objects, animate them, and integrate your own audio and video files Add interactivity, use special effects, learn morphing, and much more Check your work with the book\'s online example files and completed animations Discover new Flash toolkits and features such as Frameless Animation Use every timesaving aspect of Flash CS4, such as Library objects and Symbols Learn how to automate your drawings and animations with ActionScript 3.0 With this book, absolutely no programming is necessary to get started with Flash CS4. Flash CS4: The Missing Manual explains in jargon-free English exactly what you need to know to use Flash effectively, while avoiding common pitfalls, right from the start.','http://books.google.com/books/content?id=5lbgLdoGcusC&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 05:48:27','5lbgLdoGcusC','The Missing Manual','\"O\'Reilly Media, Inc.\"',2008,'Computers','NOT_MATURE','0.8.8.0.preview.3',755),(1137,'1250150973','Caraval: Chapter Sampler','Stephanie Garber','This excerpt from Caraval—Stephanie Garber’s sweeping tale of two sisters who escape their ruthless father when they enter the dangerous intrigue of a legendary game—contains for the first six chapters. Everyone is talking about Caraval! “Spellbinding.” —Sabaa Tahir, author of An Ember in the Ashes “Beautifully written.” —Renée Ahdieh, author of The Wrath and the Dawn “Shimmers with magic.” —Marie Rutkoski, author of The Winner’s Curse “Darkly enchanting.” —Kiersten White, author of And I Darken “Decadent.” —Roshani Chokshi, author of The Star-Touched Queen “Like stepping into a living dream.” —Stacey Lee, author of Outrun the Moon “Magnificent.” —Publishers Weekly, starred review “Destined to capture imaginations.” —Kirkus Reviews \"Ideal for fans ofThe Night Circus, Stardust, and The Hunger Games.” —SLJ','http://books.google.com/books/content?id=hy96DQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:43:11','hy96DQAAQBAJ',NULL,'Flatiron Books',2016,'Young Adult Fiction','NOT_MATURE','1.3.3.0.preview.2',57),(1138,'1250095255','Caraval','Stephanie Garber','The acclaimed New York Times bestseller Welcome, welcome to Caraval--Stephanie Garber\'s sweeping tale of the unbreakable bond between two sisters. It\'s the closest you\'ll ever find to magic in this world... Scarlett has never left the tiny island where she and her beloved sister, Tella, live with their powerful, and cruel, father. Now Scarlett\'s father has arranged a marriage for her, and Scarlett thinks her dreams of seeing Caraval, the far-away, once-a-year performance where the audience participates in the show, are over. But this year, Scarlett\'s long-dreamt of invitation finally arrives. With the help of a mysterious sailor, Tella whisks Scarlett away to the show. Only, as soon as they arrive, Tella is kidnapped by Caraval\'s mastermind organizer, Legend. It turns out that this season\'s Caraval revolves around Tella, and whoever finds her first is the winner. Scarlett has been told that everything that happens during Caraval is only an elaborate performance. But she nevertheless becomes enmeshed in a game of love, heartbreak, and magic with the other players in the game. And whether Caraval is real or not, she must find Tella before the five nights of the game are over, a dangerous domino effect of consequences is set off, and her sister disappears forever. Welcome, welcome to Caraval . . . beware of getting swept too far away. New York Times bestseller #1 IndieNext Pick Publishers Weekly Flying Start Entertainment Weekly Best 10 YA Books of 2017 Teen Vogue Best YA Book of the Year Amazon Best Book of the Year Barnes & Noble Best Book of the Year BuzzFeed Best Book of the Year \"The Hunger Games meets The Night Circus. Grade: A-.\" --Entertainment Weekly \"Impressive, original, wondrous.\" --USA Today \"Spellbinding.\" --US Weekly \"Magnificent.\" --Publishers Weekly, starred review \"I lost myself in this world.\" --Sabaa Tahir, author of An Ember in the Ashes \"Beautifully written.\" --Ren e Ahdieh, author of The Wrath and the Dawn \"Shimmers with magic.\" --Marie Rutkoski, author of The Winner\'s Curse \"Darkly enchanting.\" --Kiersten White, author of And I Darken \"Decadent.\" --Roshani Chokshi, author of The Star-Touched Queen \"Like stepping into a living dream.\" --Stacey Lee, author of Outrun the Moon \"Destined to capture imaginations.\" --Kirkus Reviews \"Ideal for fans of The Night Circus, Stardust, and The Hunger Games.\" --School Library Journal','http://books.google.com/books/content?id=kA-HDQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:43:11','kA-HDQAAQBAJ',NULL,'Macmillan',2017,'Juvenile Fiction','NOT_MATURE','1.2.2.0.preview.0',416),(1139,'1250157668','Finale','Stephanie Garber','Welcome, welcome to Finale, the third and final book in Stephanie Garber\'s #1 New York Times bestselling Caraval series A love worth fighting for. A dream worth dying for. An ending worth waiting for. It\'s been two months since the Fates were freed from a deck of cards, two months since Legend claimed the throne for his own, and two months since Tella discovered the boy she fell in love with doesn\'t really exist. With lives, empires, and hearts hanging in the balance, Tella must decide if she\'s going to trust Legend or a former enemy. After uncovering a secret that upends her life, Scarlett will need to do the impossible. And Legend has a choice to make that will forever change and define him. Caraval is over, but perhaps the greatest game of all has begun. There are no spectators this time: only those who will win, and those who will lose everything. Welcome, welcome to Finale. All games must come to an end...','http://books.google.com/books/content?id=O1J0DwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:43:11','O1J0DwAAQBAJ','A Caraval Novel',NULL,2019,'Juvenile Fiction','NOT_MATURE','0.1.2.0.preview.0',493),(1140,'9781399739672','Caraval','Stephanie Garber',NULL,'http://books.google.com/books/content?id=ocPS0AEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:43:11','ocPS0AEACAAJ','Remember,its Only a Game','Hodderscape',2024,'Fiction','NOT_MATURE','preview-1.0.0',0),(1141,'1250095336','Legendary','Stephanie Garber','The “immersive and imaginative“ (USA TODAY) games continue in the #1 NEW YORK TIMES bestseller LEGENDARY, the mesmerizing sequel to CARAVAL Donatella and Scarlett Dragna escaped their cruel father and made it out of Caraval alive, but the games aren’t over yet. What Scarlett doesn’t know is that, in order to gain their freedom, Tella made a deal with a mysterious stranger and now it’s time to pay. Except what Tella owes is something that no one has ever been able to deliver: the true name of Caraval Master Legend. Tella’s only chance at uncovering Legend’s true identity is to enter the dangerous game of Caraval once more, and win. But what will she have to sacrifice to do that? Don’t miss FINALE, the stunning conclusion to the Caraval trilogy—out now!','http://books.google.com/books/content?id=wrc3DwAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:43:11','wrc3DwAAQBAJ','A Caraval Novel','Flatiron Books',2018,'Young Adult Fiction','NOT_MATURE','2.7.7.0.preview.2',462),(1142,'1529350174','The Caraval Complete Trilogy','Stephanie Garber','\'If you ever wondered how it would feel to step into a living dream, here\'s your ticket\' - Stacey Lee Welcome to Caraval, where nothing is quite what it seems . . . Scarlett has never left the tiny isle of Trisda, pining from afar for the wonder of Caraval, a once-a-year week-long performance where the audience participates in the show. Caraval is Magic. Mystery. Adventure. And for Scarlett and her beloved sister Tella it represents freedom and an escape from their ruthless, abusive father. When the sisters\' long-awaited invitations to Caraval finally arrive, it seems their dreams have come true. But no sooner have they arrived than Tella vanishes, kidnapped by the show\'s mastermind organiser, Legend. Scarlett has been told that everything that happens during Caraval is only an elaborate performance. But nonetheless she quickly becomes enmeshed in a dangerous game of love, magic and heartbreak. And real or not, she must find Tella before the game is over, and her sister disappears forever. *************** PRAISE FOR THE CARAVAL SERIES \'Impressive, original, wondrous\' - USA Today \'Spellbinding\' - US Weekly \'Magnificent\' Publishers Weekly \'The Hunger Games meets The Night Circus\' - Entertainment Weekly \'I lost myself in this world\' - Sabaa Tahir \'Beautifully written\' - Renée Ahdieh \'Shimmers with magic\' - Marie Rutkoski','http://books.google.com/books/content?id=nXj0DwAAQBAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:43:11','nXj0DwAAQBAJ',NULL,'Hachette UK',2020,'Fiction','NOT_MATURE','1.8.8.0.preview.2',1030),(1143,'9781250225450','Caraval Boxed Set','Stephanie Garber',NULL,'http://books.google.com/books/content?id=dwMAwAEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:43:11','dwMAwAEACAAJ','Caraval / Legendary / Finale','Caraval',2019,'Young Adult Fiction','NOT_MATURE','preview-1.0.0',0),(1144,'125036888X','Caraval Holiday Collection','Stephanie Garber','A gorgeous red boxed set (4 books) of the #1 New York Times bestselling Caraval series to celebrate the publication of Spectacular! For a limited time, all four books in the #1 New York Times bestselling Caraval series are now available together in a holiday repackage with exclusive white covers and stained edges. Welcome, welcome to the world of Caraval--Stephanie Garber\'s sweeping tale of the unbreakable bond between two sisters and the game that is more than what it seems. . . . In Caraval, Scarlett has never left the tiny island where she and her beloved sister, Tella, live with their powerful and cruel father. But this year, Scarlett\'s long-dreamt of invitation to Caraval, the far-away, once-a-year performance where the audience participates in the show, finally arrives. In Legendary, the Dragna sisters should be celebrating, but Tella isn\'t yet free. She made a desperate bargain with a mysterious criminal, and what Tella owes him no one has ever been able to deliver: Caraval Master Legend\'s true name. In Finale, with lives, empires, and hearts hanging in the balance, Scarlett and Tella fight for their lives and for each other. There are no spectators this time: only those who will win, and those who will lose everything. In Spectacular, Scarlett is planning a celebration for the city while Tella is searching for the perfect gift to change Legend\'s mind about the Great Holiday. She hasn\'t found this perfect gift just yet, but surely there\'s some holiday magic swirling around. . . .','http://books.google.com/books/content?id=u87sEAAAQBAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:43:11','u87sEAAAQBAJ','Caraval, Legendary, Finale, Spectacular',NULL,2024,'Young Adult Fiction','NOT_MATURE','preview-1.0.0',0),(1145,'9783492704168','Es ist nur ein Spiel','Stephanie Garber','Die Geschichte von zwei Schwestern, die ihrem gewalttätigem Vater entkommen wollen und sich ein Leben in Freiheit wünschen. Dafür nehmen sie am magischen Spiel von Caraval teil und riskieren dabei ihr Leben. Schnell verliert man den Überblick über Realität und Fiktion. Wem kann man trauen? Ab 15',NULL,'2026-03-15 06:43:11','RYR2zwEACAAJ','',NULL,2017,NULL,'NOT_MATURE','preview-1.0.0',0),(1146,NULL,'An Anthology of South Dakota Poetry',NULL,NULL,'http://books.google.com/books/content?id=CpFLAAAAIAAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:43:12','CpFLAAAAIAAJ',NULL,NULL,1928,'American literature','NOT_MATURE','0.5.4.0.full.1',264),(1147,'0241997038','People We Meet On Vacation','Emily Henry','** SET TO BE A MAJOR NETFLIX RELEASE STARRING EMILY BADER AND TOM BLYTH! ** ------ \'One of my favourite authors\' Colleen Hoover, It Ends With Us \'A gorgeous romance\' Beth O\'Leary, The No-Show \'Loveable characters, hilarious wit and steamy sexual chemistry\' Laura Jane Williams, Our Stop *Also known as People We Meet On Vacation* ------ Two friends. Ten trips. Their last chance to fall in love... 12 YEARS AGO: Poppy and Alex meet. They hate each other, and are pretty confident they\'ll never speak again. 11 YEARS AGO: They\'re forced to share a ride home from college and by the end of it a friendship is formed. And a pact: every year, one vacation together. 10 YEARS AGO: Alex discovers his fear of flying on the way to Vancouver. Poppy holds his hand the whole way. 7 YEARS AGO: They get far too drunk and narrowly avoid getting matching tattoos in New Orleans. 2 YEARS AGO: It all goes wrong. THIS YEAR: Poppy asks Alex to join her on one last trip. A trip that will determine the rest of their lives. You and Me on Vacation is a New York Times bestselling love story for fans of When Harry Met Sally, One Day and Casey McQuiston. Get ready to travel the world, snort with laughter and - most of all - lose your heart to Poppy and Alex. ------ \'Our generation\'s answer to Nora Ephron\' Sophie Cousens, This Time Next Year \'So warm and funny\' Paige Toon, The Minute I Saw You \'The hottest book of the summer - the pages simply sizzle!\' Josie Silver, One Night on the Island \'Emily Henry is my newest automatic-buy author . . . a heartfelt, funny, tender escape that you wish could last forever\' Jodi Picoult, Wish You Were Here \'A compulsively readable book full of sparkling wit, dazzling prose and a romance that grabbed me by the heart and wouldn\'t let me go\' Abby Jiminez, Part of Your World \'Funny, and seriously sizzling\' BEST \'If whipcrack banter and sexual tension is your catnip, you\'ll adore this book\' Sally Thorne, The Hating Game \'What an absolute flipping triumph of a novel!!! I LOVED it \' Emma Cooper, It Was Always You Emily Henry, Sunday Times bestseller, May 2024','http://books.google.com/books/content?id=xWNjEAAAQBAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:44:47','xWNjEAAAQBAJ',NULL,'Random House',2022,'Fiction','NOT_MATURE','1.7.8.0.preview.2',336),(1148,'0593956222','People We Meet on Vacation','Emily Henry','Emily Henry’s dazzling New York Times bestselling novel now in this special hardcover collector’s edition with: • A gleaming redesigned cover • Stunning illustrated endpapers and matching sprayed edges that will take you poolside in sunny Palm Springs • A copper foil–stamped case, and… • A new letter from the author and exclusive postcard art Two best friends. Ten summer trips. One last chance to fall in love. Poppy and Alex. Alex and Poppy. They have nothing in common. She’s a wild child; he wears khakis. She has insatiable wanderlust; he prefers to stay home with a book. And somehow, ever since a fateful car share home from college many years ago, they are the very best of friends. For most of the year they live far apart—she’s in New York City, and he’s in their small hometown—but every summer, for a decade, they have taken one glorious week of vacation together. Until two years ago, when they ruined everything. They haven\'t spoken since. Poppy has everything she should want, but she’s stuck in a rut. When someone asks when she was last truly happy, she knows, without a doubt, it was on that ill-fated, final trip with Alex. And so, she decides to convince her best friend to take one more vacation together—lay everything on the table, make it all right. Miraculously, he agrees. Now she has a week to fix everything. If only she can get around the one big truth that has always stood quietly in the middle of their seemingly perfect relationship. What could possibly go wrong?','http://books.google.com/books/content?id=antCEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:44:48','antCEQAAQBAJ','Deluxe Edition','Penguin Group',2025,'Fiction','NOT_MATURE','1.1.1.0.preview.1',385),(1149,NULL,'People We Meet On Vacation By Emily Henry','Easy Reads','People We Meet On Vacation is a warm, character driven story about friendship, timing, and the risk of telling the truth. Poppy and Alex share one tradition. One vacation every year. She loves chaos and stories. He values structure and quiet. For a decade, trips turn into memories shaped by late nights, missed trains, and conversations which matter more than destinations. Two years ago, something breaks their rhythm. They stop speaking. Poppy decides to fix it. One final trip. One chance to face what went wrong. As past vacations unfold beside the present, feelings long ignored surface with force. The story explores how love grows from familiarity and how fear keeps people silent. Emily Henry delivers an honest look at connection, regret, and the moment you choose to stop running from what your heart wants. Disclaimer: You are viewing a summary of the content from the book, People We Meet On Vacation. The summary\'s contents are not poised to replace the original book. It is meant as a complement to enhance the reader\'s understanding.','http://books.google.com/books/content?id=jzq3EQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:44:48','jzq3EQAAQBAJ','Summary & Analysis','Easy Reads',1970,'Fiction','NOT_MATURE','1.1.1.0.preview.3',30),(1150,NULL,'People We Meet on Vacation: Collector\'s Edition (Netflix Tie-In)','Emily Henry','NOW A NETFLIX FILM! • Emily Henry’s sparkling New York Times bestselling novel—now in a beautiful movie tie-in collector’s edition featuring: · Exclusive Netflix movie art · Gorgeous, leafy sprayed edges · A bonus essay by Emily Henry about the novel\'s journey from page to screen! Two best friends. Ten summer trips. One last chance to fall in love. Poppy and Alex. Alex and Poppy. They have nothing in common. She\'s a wild child; he wears khakis. She has insatiable wanderlust; he prefers to stay home with a book. And somehow, ever since a fateful car share home from college many years ago, they are the very best of friends. For most of the year they live far apart—she\'s in New York City, and he\'s in their small hometown—but every summer, for a decade, they have taken one glorious week of vacation together. Until two years ago, when they ruined everything. They haven\'t spoken since. Poppy has everything she should want, but she\'s stuck in a rut. When someone asks when she was last truly happy, she knows, without a doubt, it was on that ill-fated, final trip with Alex. And so, she decides to convince her best friend to take one more vacation together—lay everything on the table, make it all right. Miraculously, he agrees. Now she has a week to fix everything. If only she can get around the one big truth that has always stood quietly in the middle of their seemingly perfect relationship. What could possibly go wrong?','http://books.google.com/books/content?id=OLqFEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:44:48','OLqFEQAAQBAJ',NULL,'Penguin Group',2025,'Fiction','NOT_MATURE','1.1.1.0.preview.1',401),(1151,NULL,'Summary of People We Meet on Vacation By Emily Henry','Peter Cuomo','A high-quality summary of Emily Henry´s book People We Meet on Vacation including chapter details and analysis of the main themes of the original book. About the original book: Poppy and Alex. There isn\'t a single thing they share in common. He\'s dressed in khakis and she\'s a wild youngster. He loves to stay at home with a book, while she has an unquenchable wanderlust. And they\'ve been the best of friends ever since a disastrous car ride home from college many years ago. They live far apart for the majority of the year—she in New York City, and he in their little hometown—but they have spent one lovely week of vacation together every summer for the past decade. Until they damaged everything two years ago. Since then, they haven\'t talked. Poppy has all she needs, but she can\'t seem to get out of her rut. When others ask her when she was last really happy, she knows it was on that final, ill-fated vacation with Alex. As a result, she resolves to persuade her closest friend to spend one more trip with her—to lay everything out on the table and make things okay. Surprisingly, he agrees. She now has a week to get things in order. If she could just get over the one major fact that has always lurked in the background of their seemingly ideal relationship. What\'s the worst that might happen?','http://books.google.com/books/content?id=rLlZEAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:44:48','rLlZEAAAQBAJ','People We Meet on Vacation Book Complete Analysis & Study Guide by Peter Cuomo','Peter Cuomo',1970,'Study Aids','NOT_MATURE','0.2.3.0.preview.3',51),(1152,NULL,'Summary Of: People We Meet on Vacation By: Emily Henry','Mehdi Sarah','DISCLAIMER: The author and the publisher do not warrant the accuracy of the information, text and graphics contained within and does not hold any responsibility for errors, omissions or contrary interpretation of the subject matter herein. The use of this book implies your acceptance of this disclaimer. This is an unofficial journal meant for educational, personal and informational purposes only. This book has not been authorized, approved, licensed or endorsed by the author of the original book or his/her publisher and any of their licensees or affiliates However, companion books are legal and our intention in publishing this book is sincere, as readers can use this book alongside the main text. This book is to be used as a companion book and not as a substitute to the main book. SУNОРЅІЅ. Poppy and Alеx. Alex аnd Poppy. Thеу hаvе nоthіng іn common. Shе\'ѕ a wіld сhіld; hе wears khakis. Shе hаѕ іnѕаtіаblе wаndеrluѕt; hе prefers to ѕtау home with a bооk. And ѕоmеhоw, еvеr ѕіnсе a fаtеful car share hоmе frоm соllеgе mаnу уеаrѕ ago, thеу аrе the vеrу bеѕt of frіеndѕ. Fоr mоѕt оf thе уеаr thеу live fаr apart-she\'s in Nеw York Cіtу, аnd hе\'ѕ іn thеіr ѕmаll hоmеtоwn-but еvеrу ѕummеr, for a dесаdе, thеу hаvе tаkеn one glоrіоuѕ wееk оf vacation tоgеthеr. Untіl two уеаrѕ ago, whеn they ruined everything. Thеу hаvеn\'t ѕроkеn ѕіnсе. Poppy hаѕ еvеrуthіng ѕhе ѕhоuld wаnt, but ѕhе\'ѕ ѕtuсk in a rut. When ѕоmеоnе asks when ѕhе was lаѕt trulу hарру, she knоwѕ, without a doubt, іt wаѕ оn thаt ill-fated, final trip wіth Alex. And so, ѕhе dесіdеѕ to соnvіnсе her bеѕt friend tо take оnе mоrе vасаtіоn tоgеthеr-lау еvеrуthіng оn thе tаblе, make it аll rіght. Miraculously, he аgrееѕ. Nоw ѕhе hаѕ a wееk tо fіx everything. If only she саn gеt аrоund thе оnе big truth thаt hаѕ аlwауѕ ѕtооd quietly іn the middle оf thеіr ѕееmіnglу perfect rеlаtіоnѕhір. Whаt соuld роѕѕіblу gо wrоng? NOTE: This summary wasn\'t written with the intention of replacing the original book, rather it was made to act as a guide for you to enjoy and understand the original book.',NULL,'2026-03-15 06:44:48','WjK9zgEACAAJ',NULL,NULL,2021,NULL,'NOT_MATURE','preview-1.0.0',24),(1153,'0593953665','Emily Henry 3-Book Boxed Set','Emily Henry','From #1 New York Times bestselling author Emily Henry comes a sparkling and stylish boxed set of the first three novels that started the phenomenon: Beach Read, People We Meet on Vacation, and Book Lovers. Showcasing Emily Henry\'s trademark elevated romantic fiction, these three novels are filled to the brim with wit, banter, and joy, while also being relatable, genuinely funny, and cathartic, as Emily tackles themes that resonate deeply with her readers. Beach Read A romance author who no longer believes in love and a literary writer stuck in a rut engage in a summer-long challenge that may just upend everything they believe about happily-ever-afters. People We Meet on Vacation Alex and Poppy are the best of friends, and every summer they have taken one glorious week of vacation together--until two years ago, when they ruined everything. Now, Poppy wants her best friend back and convinces Alex to go on one more trip together: one week to fix everything. Book Lovers A cutthroat literary agent agrees to accompany her sister on a trip to Sunshine Falls, NC, in order to become the heroine in her own story, only to keep bumping into the brooding editor from back in the city.','http://books.google.com/books/content?id=deoTEQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:44:48','deoTEQAAQBAJ','Beach Read, People We Meet on Vacation, and Book Lovers','Penguin Group',2024,'Fiction','NOT_MATURE','1.1.1.0.preview.1',402),(1154,NULL,'People We Meet on Vacation','Richard Turner','Poppy and Alex. Alex and Poppy. They have nothing in common. She\'s a wild child; he wears khakis. She has insatiable wanderlust; he prefers to stay home with a book. And somehow, ever since a fateful car share home from college many years ago, they are the very best of friends. For most of the year they live far apart--she\'s in New York City, and he\'s in their small hometown--but every summer, for a decade, they have taken one glorious week of vacation together. Until two years ago, when they ruined everything. They haven\'t spoken since. Poppy has everything she should want, but she\'s stuck in a rut. When someone asks when she was last truly happy, she knows, without a doubt, it was on that ill-fated, final trip with Alex. And so, she decides to convince her best friend to take one more vacation together--lay everything on the table, make it all right. Miraculously, he agrees.',NULL,'2026-03-15 06:44:48','CuY9zgEACAAJ',NULL,NULL,2021,NULL,'NOT_MATURE','preview-1.0.0',120),(1155,NULL,'People We Meet on Vacation','Chad M McMahon','People We Meet on Vacation: The Movie Review Guide is the warm, smart, and heartfelt companion for anyone who cares about story, chemistry, and character. This book is made for readers who loved the original novel and for viewers who cannot wait to watch the onscreen version. It explores how a slow friendship turns into something real, and why that connection matters. You\'ll get a clear, thoughtful look at how the romance between Poppy and Alex is built, why it feels honest, and how the final trip raises the stakes for both of them. You will also understand how a modern romantic comedy still has the power to move people. Inside, you\'ll find a full discussion of casting and why it matters. You\'ll see how Emily Bader as Poppy Wright and Tom Blyth as Alex Nilsen carry the heart of the story, how their energy shapes the tension, and how that energy supports the core \"best friends trying not to admit they\'re in love\" hook. You\'ll get insight on performances from Sarah Catherine Hook, Jameela Jamil as Swapna Bakshi-Highsmith, Lucien Laviscount, Lukas Gage, Miles Heizer, Alice Lee, Tommy Do, Alan Ruck, Molly Shannon, and Michael A. Newcomer, and how each one adds texture, humor, and warmth. You\'ll learn how real chemistry on screen helps carry a romance that spans years. This guide looks at how the bestselling book became a film and what changes when a private joke, a shared hotel room, or a stolen glance is no longer on the page but right in front of you. It studies the tropes that fans love, including friends to lovers romance story, slow burn friends to lovers, and the emotional pull of a summer vacation love story. It also explores how a decade of memories turns into a single story for the screen, and how that shift serves both book lovers and new viewers. Whether you\'re searching for people we meet on vacation movie review, you\'re curious about people we meet on vacation book to movie, or you\'re an Emily Henry reader looking for an emily henry fans guide, this companion breaks down what makes this adaptation special. It highlights poppy and alex love story, celebrates cast chemistry with a full cast and chemistry review people we meet on vacation, and serves as the most complete romantic comedy movie guide for People We Meet on Vacation (film). By the end, you\'ll be able to explain why this is not just a people we meet on vacation review, but the people we meet on vacation adaptation fans have been waiting for, and the the people we meet on vacation movie review that helps you watch with new eyes, starting from the heart of the people we meet on vacation book.','http://books.google.com/books/content?id=oaWn0QEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:44:48','oaWn0QEACAAJ','The Movie Review Guide: Chemistry, Performances, and the Summer Trip Love Story','Independently Published',2025,'Performing Arts','NOT_MATURE','preview-1.0.0',0),(1156,NULL,'PEOPLE WE MEET ON VACATION','Robert S. Bell','Two Best Friends, One Life-Changing Reunion: Discover the Love and Adventure That Could Rewrite Their Future\" In this captivating exploration of People We Meet on Vacation, we take a deeper dive into the unforgettable journey of Poppy and Alex—two best friends whose bond evolves from carefree vacations to something much more profound. Over the course of their annual summer getaways, they share laughs, adventures, and beautiful destinations. But when their friendship is put to the ultimate test, secrets, unspoken feelings, and years of emotional silence threaten to unravel everything they\'ve built. As they reunite in the stunning city of Barcelona, the weight of their shared past looms large. Will they overcome their fears of love and vulnerability, or will the complexities of friendship and romance be too much to bridge? This is not just a story about travel—it’s a journey into the heart of human connection, the highs and lows of love, and the importance of facing the truth, no matter how difficult. Through intimate insights, behind-the-scenes moments, and reflections on what makes this story so enduringly powerful, People We Meet on Vacation explores themes of self-discovery, personal growth, and the transformative power of love and friendship. If you’ve ever wondered what it takes to heal a broken bond, rekindle a lost connection, or take a leap of faith in love, this book is for you. Dive deep into the world of Poppy and Alex, and discover the journey that changed their lives forever. Grab your copy now and experience the emotional rollercoaster of rekindling love, discovering yourself, and embracing the adventure of life!','http://books.google.com/books/content?id=-eK4EQAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:44:48','-eK4EQAAQBAJ','A Deep Dive into Love, Friendship, and Life-Changing Journeys in the Hit Romantic Comedy','Robert S. Bell',1970,'Fiction','NOT_MATURE','preview-1.0.0',102),(1157,'1526634244','A Court of Thorns and Roses','Sarah J. Maas','Lose yourself in a world so sumptuous that you may never return home ... The tantalising start to a seductive fantasy series from global #1 bestselling author Sarah J. Maas for fans of E.L. James and Deborah Harkness','http://books.google.com/books/content?id=VswAEAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:58:30','VswAEAAAQBAJ','Enter the EPIC fantasy worlds of Sarah J Maas with the breath-taking first book in the GLOBALLY BESTSELLING ACOTAR series','Bloomsbury Publishing',2020,'Fiction','NOT_MATURE','1.3.3.0.preview.1',451),(1158,'1639730087','A Court of Thorns and Roses eBook Bundle','Sarah J. Maas','Lose yourself in the seductive world of the Court of Thorns and Roses series (ACOTAR) by #1 global bestselling phenomenon Sarah J. Maas with this five-eBook bundle.','http://books.google.com/books/content?id=yzZ7EAAAQBAJ&printsec=frontcover&img=1&zoom=1&edge=curl&source=gbs_api','2026-03-15 06:58:31','yzZ7EAAAQBAJ','A 5 Book Bundle','Bloomsbury Publishing USA',2022,'Fiction','NOT_MATURE','2.6.5.0.preview.3',2962),(1159,NULL,'A Court of Thorns and Roses Paperback Box Set (5 Books)','Sarah J. Maas',NULL,'http://books.google.com/books/content?id=N2tZ0QEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:58:31','N2tZ0QEACAAJ',NULL,NULL,2022,'Fiction','NOT_MATURE','preview-1.0.0',0),(1160,NULL,'A Court of Thorns and Roses Full Series 5 Book Box Set by Sarah J. Maas','Sarah J. Maas','Lose yourself in the seductive world of the Court of Thorns and Roses (ACOTAR) series by #1 global bestselling phenomenon Sarah J. Maas with this gorgeous box set that includes all five paperbacks.','http://books.google.com/books/content?id=SI3Y0QEACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api','2026-03-15 06:58:31','SI3Y0QEACAAJ',NULL,NULL,2023,'Family & Relationships','